extends CharacterBody3D

@export var walk_speed: float = {{walk_speed}}
@export var sprint_speed: float = {{sprint_speed}}
@export var crouch_speed: float = {{crouch_speed}}
@export var jump_velocity: float = {{jump_velocity}}
@export var mouse_sensitivity: float = {{mouse_sensitivity}}
@export var head_bob_amount: float = {{head_bob_amount}}

@onready var camera: Camera3D = $Camera3D
@onready var collision_shape: CollisionShape3D = $CollisionShape3D

var _gravity: float = ProjectSettings.get_setting("physics/3d/default_gravity")
var _head_bob_timer: float = 0.0

func _ready():
	Input.set_mouse_mode(Input.MOUSE_MODE_CAPTURED)

func _input(event):
	if event is InputEventMouseMotion and Input.get_mouse_mode() == Input.MOUSE_MODE_CAPTURED:
		rotate_y(-event.relative.x * mouse_sensitivity * 0.01)
		camera.rotate_x(-event.relative.y * mouse_sensitivity * 0.01)
		camera.rotation.x = clamp(camera.rotation.x, -PI/2, PI/2)

func _physics_process(delta):
	var speed = walk_speed
	if Input.is_action_pressed("sprint"):
		speed = sprint_speed
	elif Input.is_action_pressed("crouch"):
		speed = crouch_speed

	velocity.y += -_gravity * delta

	if Input.is_action_just_pressed("jump") and is_on_floor():
		velocity.y = jump_velocity

	var input_dir = Input.get_vector("move_left", "move_right", "move_forward", "move_back")
	var direction = (transform.basis * Vector3(input_dir.x, 0, input_dir.y)).normalized()
	if direction:
		velocity.x = direction.x * speed
		velocity.z = direction.z * speed
		_head_bob_timer += delta * speed
	else:
		velocity.x = move_toward(velocity.x, 0, speed)
		velocity.z = move_toward(velocity.z, 0, speed)

	move_and_slide()

	# Head-bob
	if head_bob_amount > 0 and is_on_floor() and direction.length() > 0:
		camera.position.y = {{camera_height}} + sin(_head_bob_timer * 10.0) * head_bob_amount
